import React from 'react';
import TodoList from './components/TodoList';
import TodoForm from './components/TodoForm';
import useTodos from './hooks/useTodos';

function App() {
  const { todos, addTodo, toggleComplete, deleteTodo, editTodo } = useTodos();

  return (
    <div className="min-h-screen bg-gradient-to-br from-primary-500 to-primary-700 font-sans text-gray-900 flex items-center justify-center p-4 sm:p-6 lg:p-8">
      <div className="bg-white shadow-2xl rounded-xl p-6 sm:p-8 lg:p-10 w-full max-w-md mx-auto transform transition-all duration-300 hover:shadow-3xl">
        <h1 className="text-4xl font-display font-extrabold text-center text-primary-600 mb-8 tracking-tight">
          My Daily Tasks
        </h1>

        <TodoForm addTodo={addTodo} />

        <TodoList
          todos={todos}
          toggleComplete={toggleComplete}
          deleteTodo={deleteTodo}
          editTodo={editTodo}
        />

        {todos.length === 0 && (
          <p className="text-center text-gray-500 mt-8 text-lg italic">
            No tasks yet! Add some above.
          </p>
        )}
      </div>
    </div>
  );
}

export default App;

