import React, { useState } from 'react';
import { Plus } from 'lucide-react';

const TodoForm = ({ addTodo }) => {
  const [task, setTask] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (task.trim()) {
      addTodo(task.trim());
      setTask('');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="flex items-center gap-2 p-4 bg-white rounded-lg shadow-md mb-6">
      <label htmlFor="todo-input" className="sr-only">Add a new task</label>
      <input
        type="text"
        id="todo-input"
        className="flex-grow p-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 text-gray-800 placeholder-gray-400 text-base transition-all duration-200 ease-in-out"
        value={task}
        onChange={(e) => setTask(e.target.value)}
        placeholder="What needs to be done?"
        aria-label="Add a new task"
      />
      <button
        type="submit"
        className="flex items-center justify-center p-3 bg-primary-500 text-white rounded-lg shadow-md hover:bg-primary-600 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:ring-offset-2 transition-all duration-200 ease-in-out active:scale-95"
        aria-label="Add task"
      >
        <Plus className="w-5 h-5" />
        <span className="ml-2 hidden sm:inline">Add Task</span>
      </button>
    </form>
  );
};

export default TodoForm;

