import React, { useState, useEffect, useCallback } from 'react';
import TodoForm from './TodoForm';
import TodoItem from './TodoItem';
import useTodos from '../hooks/useTodos';
import { ListTodo, CheckCircle2, XCircle, Loader2 } from 'lucide-react';

const TodoList = () => {
  const { todos, addTodo, toggleComplete, deleteTodo, editTodo, loading, error } = useTodos();
  const [filter, setFilter] = useState('all'); // 'all', 'active', 'completed'
  const [searchTerm, setSearchTerm] = useState('');

  const filteredTodos = todos.filter(todo => {
    const matchesFilter =
      filter === 'all' ||
      (filter === 'active' && !todo.completed) ||
      (filter === 'completed' && todo.completed);
    const matchesSearch = todo.text.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  const handleFilterChange = useCallback((newFilter) => {
    setFilter(newFilter);
  }, []);

  const handleSearchChange = useCallback((e) => {
    setSearchTerm(e.target.value);
  }, []);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] bg-white rounded-xl shadow-lg p-8">
        <Loader2 className="animate-spin text-primary-500 w-12 h-12 mb-4" />
        <p className="text-lg text-gray-700 font-medium">Loading your tasks...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] bg-red-50 rounded-xl shadow-lg p-8 text-red-700">
        <XCircle className="w-12 h-12 mb-4" />
        <p className="text-lg font-medium">Error loading tasks: {error.message}</p>
        <p className="text-sm text-gray-600 mt-2">Please try refreshing the page.</p>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto p-4 sm:p-6 lg:p-8 bg-gradient-to-br from-primary-50 to-blue-100 rounded-3xl shadow-2xl">
      <h1 className="text-4xl font-display font-extrabold text-center text-primary-800 mb-8 drop-shadow-sm">
        <ListTodo className="inline-block w-10 h-10 mr-3 text-primary-600" />
        My Daily Tasks
      </h1>

      <TodoForm addTodo={addTodo} />

      <div className="mt-8 bg-white rounded-2xl shadow-lg p-6">
        <div className="flex flex-col sm:flex-row items-center justify-between mb-6 gap-4">
          <div className="relative w-full sm:w-auto flex-grow">
            <input
              type="text"
              placeholder="Search tasks..."
              value={searchTerm}
              onChange={handleSearchChange}
              aria-label="Search tasks"
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-400 focus:border-transparent outline-none transition-all duration-200 ease-in-out text-gray-700"
            />
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>

          <div className="flex space-x-2 sm:space-x-3 w-full sm:w-auto justify-center">
            <button
              onClick={() => handleFilterChange('all')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ease-in-out
                ${filter === 'all' ? 'bg-primary-500 text-white shadow-md' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
              aria-pressed={filter === 'all'}
            >
              All
            </button>
            <button
              onClick={() => handleFilterChange('active')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ease-in-out
                ${filter === 'active' ? 'bg-primary-500 text-white shadow-md' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
              aria-pressed={filter === 'active'}
            >
              Active
            </button>
            <button
              onClick={() => handleFilterChange('completed')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ease-in-out
                ${filter === 'completed' ? 'bg-primary-500 text-white shadow-md' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
              aria-pressed={filter === 'completed'}
            >
              Completed
            </button>
          </div>
        </div>

        {filteredTodos.length === 0 ? (
          <div className="text-center py-10 text-gray-500">
            <CheckCircle2 className="w-16 h-16 mx-auto mb-4 text-gray-300" />
            <p className="text-xl font-medium">No tasks found for this filter or search.</p>
            {todos.length > 0 && filter !== 'all' && (
              <p className="text-md mt-2">Try changing your filter or search term.</p>
            )}
            {todos.length === 0 && (
              <p className="text-md mt-2">Start by adding a new task above!</p>
            )}
          </div>
        ) : (
          <ul className="space-y-4">
            {filteredTodos.map(todo => (
              <TodoItem
                key={todo.id}
                todo={todo}
                toggleComplete={toggleComplete}
                deleteTodo={deleteTodo}
                editTodo={editTodo}
              />
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

export default TodoList;

